class SORTracker:

    def __init__(self):
        self.locations = []
        self.index = 0

    def add(self, name: str, score: int) -> None:
        self.locations.append((-score, name))
        self.locations.sort()

    def get(self) -> str:
        return self.locations[self.index][1]
        self.index += 1
